const AUTH_STORAGE_KEY = "@mvp_auth_v1";

async function authStorageGet() {
  const raw = await AsyncStorage.getItem(AUTH_STORAGE_KEY);
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object") return null;
    return parsed;
  } catch {
    return null;
  }
}

async function authStorageSet(session) {
  await AsyncStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(session));
}

async function authStorageClear() {
  await AsyncStorage.removeItem(AUTH_STORAGE_KEY);
}

function isValidSession(session) {
  if (!session) return false;
  if (typeof session !== "object") return false;
  if (!session.token || typeof session.token !== "string") return false;
  if (!session.user || typeof session.user !== "object") return false;
  return true;
}

