const AuthContext = React.createContext(null);

const initialAuthState = {
  bootstrapping: true,
  token: null,
  user: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case "BOOTSTRAP_DONE":
      return { ...state, bootstrapping: false };
    case "RESTORE":
      return {
        ...state,
        token: action.token,
        user: action.user,
        bootstrapping: false,
      };
    case "SIGN_IN":
      return { ...state, token: action.token, user: action.user };
    case "SIGN_OUT":
      return { ...state, token: null, user: null };
    case "UPDATE_USER":
      return { ...state, user: { ...(state.user || {}), ...(action.user || {}) } };
    default:
      return state;
  }
}

function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialAuthState);
  const [busy, setBusy] = useState(false);

  const bootstrap = useCallback(async () => {
    try {
      const session = await authStorageGet();
      if (!isValidSession(session)) {
        dispatch({ type: "BOOTSTRAP_DONE" });
        return;
      }

      try {
        const user = await apiMe(session.token);
        const restored = { token: session.token, user };
        await authStorageSet(restored);
        dispatch({ type: "RESTORE", token: restored.token, user: restored.user });
      } catch (e) {
        await authStorageClear();
        dispatch({ type: "BOOTSTRAP_DONE" });
      }
    } catch {
      dispatch({ type: "BOOTSTRAP_DONE" });
    }
  }, []);

  useEffect(() => {
    bootstrap();
  }, [bootstrap]);

  const signIn = useCallback(async (email, password) => {
    setBusy(true);
    try {
      const session = await apiLogin({ email, password });
      if (!isValidSession(session)) throw new Error("Invalid session from server");
      await authStorageSet(session);
      dispatch({ type: "SIGN_IN", token: session.token, user: session.user });
      return true;
    } finally {
      setBusy(false);
    }
  }, []);

  const signOut = useCallback(async () => {
    setBusy(true);
    try {
      await authStorageClear();
      dispatch({ type: "SIGN_OUT" });
    } finally {
      setBusy(false);
    }
  }, []);

  const value = useMemo(
    () => ({
      bootstrapping: state.bootstrapping,
      token: state.token,
      user: state.user,
      isAuthenticated: !!state.token,
      busy,
      signIn,
      signOut,
      setUser: async (partialUser) => {
        dispatch({ type: "UPDATE_USER", user: partialUser });
        const current = await authStorageGet();
        const merged = {
          token: state.token,
          user: { ...(current?.user || state.user || {}), ...(partialUser || {}) },
        };
        if (isValidSession(merged)) await authStorageSet(merged);
      },
      refreshMe: async () => {
        if (!state.token) return;
        const user = await apiMe(state.token);
        dispatch({ type: "UPDATE_USER", user });
        const merged = { token: state.token, user };
        if (isValidSession(merged)) await authStorageSet(merged);
      },
    }),
    [state.bootstrapping, state.token, state.user, busy, signIn, signOut]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

function useAuth() {
  const ctx = React.useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
}

